// AdminMutation returns AdminMutationResolver implementation.
func (r *Resolver) AdminMutation() AdminMutationResolver { return &adminMutationResolver{r} }

// AdminQuery returns AdminQueryResolver implementation.
func (r *Resolver) AdminQuery() AdminQueryResolver { return &adminQueryResolver{r} }

type (
	adminMutationResolver struct{ *Resolver }
	adminQueryResolver    struct{ *Resolver }
)

func mapAdminUser(user *domain.AdminUser) *model.AdminUser {
	if user == nil {
		return nil
	}

	return &model.AdminUser{
		ID:                    user.ID,
		Name:                  toOptionalAdminString(user.Name),
		Username:              toOptionalAdminString(user.Username),
		AvatarURL:             toOptionalAdminAvatarURL(user.AvatarURL),
		Email:                 appscalars.Email(user.Email),
		PendingEmail:          toOptionalAdminEmail(user.PendingEmail),
		PendingEmailExpiresAt: user.PendingEmailExpiresAt,
		GoogleLinked:          strings.TrimSpace(user.GoogleSubject) != "",
		GoogleEmail:           toOptionalAdminEmail(user.GoogleEmail),
		GoogleLinkedAt:        user.GoogleLinkedAt,
		GithubLinked:          strings.TrimSpace(user.GithubSubject) != "",
		GithubEmail:           toOptionalAdminEmail(user.GithubEmail),
		GithubLinkedAt:        user.GithubLinkedAt,
		Roles:                 append([]string{}, user.Roles...),
	}
}

func toOptionalAdminProfileName(value string) *string {
	return toOptionalAdminString(value)
}

func toOptionalAdminUsername(value string) *string {
	return toOptionalAdminString(value)
}

func toOptionalAdminEmail(value string) *appscalars.Email {
	trimmed := strings.TrimSpace(strings.ToLower(value))
	if trimmed == "" {
		return nil
	}

	resolved := appscalars.Email(trimmed)
	return &resolved
}

func toOptionalAdminAvatarURL(value string) *appscalars.URL {
	return toOptionalAdminURL(value)
}

func toOptionalAdminURL(value string) *appscalars.URL {
	trimmed := strings.TrimSpace(value)
	if trimmed == "" {
		return nil
	}

	resolved := appscalars.URL(trimmed)
	return &resolved
}

func toOptionalAdminDate(value string) *appscalars.Date {
	trimmed := strings.TrimSpace(value)
	if trimmed == "" {
		return nil
	}

	resolved := appscalars.Date(trimmed)
	return &resolved
}

func mapAdminDashboard(payload *domain.AdminDashboard) *model.AdminDashboard {
	if payload == nil {
		return &model.AdminDashboard{}
	}

	return &model.AdminDashboard{
		TotalPosts:       payload.TotalPosts,
		TotalSubscribers: payload.TotalSubscribers,
		TopViewedPosts:   mapAdminDashboardPosts(payload.TopViewedPosts),
		TopLikedPosts:    mapAdminDashboardPosts(payload.TopLikedPosts),
		ContentHealth:    mapAdminDashboardContentHealth(payload.ContentHealth),
	}
}

func mapAdminDashboardPosts(items []domain.AdminDashboardPostMetric) []*model.AdminDashboardPost {
	mapped := make([]*model.AdminDashboardPost, 0, len(items))
	for _, item := range items {
		mapped = append(mapped, &model.AdminDashboardPost{
			PostID:        item.PostID,
			Title:         item.Title,
			Locale:        appscalars.Locale(item.Locale),
			PublishedDate: appscalars.Date(item.PublishedDate),
			Hits:          int(item.Hits),
			Likes:         int(item.Likes),
		})
	}

	return mapped
}

func mapAdminDashboardContentHealth(value domain.AdminDashboardContentHealth) *model.AdminDashboardContentHealth {
	return &model.AdminDashboardContentHealth{
		LocalePairCoverage:  value.LocalePairCoverage,
		MissingTranslations: value.MissingTranslations,
		MissingThumbnails:   value.MissingThumbnails,
		LatestUpdatedPosts:  mapAdminDashboardUpdatedPosts(value.LatestUpdatedPosts),
		DominantCategory:    mapAdminDashboardCategory(value.DominantCategory),
	}
}

